import{_ as i,C as r,o as n,c as s,j as a,a as t,E as l,ag as c}from"./chunks/framework.BZohXCq9.js";const b=JSON.parse('{"title":"INSTALACIÓN Y REQUISITOS","description":"","frontmatter":{},"headers":[],"relativePath":"maxstaff/index.md","filePath":"maxstaff/index.md"}'),d={name:"maxstaff/index.md"};function u(p,e,f,g,m,h){const o=r("Badge");return n(),s("div",null,[a("p",null,[e[0]||(e[0]=a("strong",null,"INSIGNIAS:",-1)),e[1]||(e[1]=t()),l(o,{type:"tip",text:"Premium"})]),e[2]||(e[2]=c('<h1 id="instalacion-y-requisitos" tabindex="-1">INSTALACIÓN Y REQUISITOS <a class="header-anchor" href="#instalacion-y-requisitos" aria-label="Permalink to &quot;INSTALACIÓN Y REQUISITOS&quot;">​</a></h1><blockquote><p>En esta sección aprenderás cómo instalar <strong>MaxStaff</strong> en tu servidor y realizar la configuración inicial básica para que el plugin funcione de buena manera, como siempre tienes el servidor de discord <a href="https://discord.gg/Vr46JHm2kd" target="_blank" rel="noreferrer">https://discord.gg/Vr46JHm2kd</a></p></blockquote><h2 id="_1-requisitos-del-servidor" tabindex="-1">1. Requisitos del servidor <a class="header-anchor" href="#_1-requisitos-del-servidor" aria-label="Permalink to &quot;1. Requisitos del servidor&quot;">​</a></h2><blockquote><p>Antes de continuar, asegúrate de que tu entorno cumpla con los siguientes requisitos:</p></blockquote><ul><li><strong>Versión de Minecraft:</strong> 1.19.x (Probado específicamente en 1.19.4).</li><li><strong>Java:</strong> Versión 17 o superior.</li><li><strong>Software del servidor:</strong> Paper, Purpur, Puperfish o cualquier fork compatible con la API de Paper.</li></ul><h2 id="_2-dependencias-opcionales" tabindex="-1">2. Dependencias opcionales <a class="header-anchor" href="#_2-dependencias-opcionales" aria-label="Permalink to &quot;2. Dependencias opcionales&quot;">​</a></h2><blockquote><p>Aunque el plugin funciona por sí solo, recomendamos instalar:</p></blockquote><ul><li><a href="https://www.spigotmc.org/resources/placeholderapi.6245/" target="_blank" rel="noreferrer">PlaceholderAPI</a>: Necesario para mostrar estadísticas de sanciones y estados del staff en otros plugins (Scoreboards, TabLists, etc.). Esto es recomendado si quieres tener mas información de lo que sucede en tu servidor, puedes encontrar los placeholder de <strong>MaxStaff</strong> en la sección de <a href="/maxstaff/placeholderapi.html">Placeholders MaxStaff</a></li></ul><h2 id="_3-guia-de-instalacion" tabindex="-1">3. Guía de instalación <a class="header-anchor" href="#_3-guia-de-instalacion" aria-label="Permalink to &quot;3. Guía de instalación&quot;">​</a></h2><ul><li>Descarga el archivo <strong>.jar</strong> de la última versión de <strong>MaxStaff</strong>.</li><li>Sube el archivo a la carpeta <code>/plugins/</code> de tu servidor de Minecraft.</li><li>Reinicia el servidor (o usa un cargador de plugins) para generar los archivos de configuración.</li><li>¡Listo! El plugin ahora estará activo con la configuración por defecto.</li></ul><h2 id="_4-configuracion-inicial" tabindex="-1">4. Configuración Inicial <a class="header-anchor" href="#_4-configuracion-inicial" aria-label="Permalink to &quot;4. Configuración Inicial&quot;">​</a></h2><blockquote><p>Por defecto, el plugin se genera en inglés. Sigue estos pasos para cambiarlo a español:</p></blockquote><ol><li>Ve a la carpeta <code>/plugins/MaxStaff/</code>.</li><li>Abre el archivo <code>config.yml</code>.</li><li>Busca la opción <code>language</code> dentro de la sección <code>general</code>.</li><li>Cambia <code>&quot;en&quot;</code> por <code>&quot;es&quot;</code>.</li></ol>',13))])}const _=i(d,[["render",u]]);export{b as __pageData,_ as default};
